import type { SessionTask } from '../types/session';
import type { UsmleStep, UsmleDiscipline, UsmleQuestionFormat } from '../types/usmle';

interface UsmleMcqInput {
  label: string;
  correct: boolean;
  explanation: string;
}

function usmle(
  id: string,
  step: UsmleStep,
  discipline: UsmleDiscipline,
  title: string,
  prompt: string,
  options: UsmleMcqInput[],
  explanation: string,
  format: UsmleQuestionFormat = 'single-best-answer',
  imageSrc?: string,
  imageCaption?: string,
): SessionTask {
  const builtOptions = options.map((o, i) => ({
    id: `${id}-opt-${i}`,
    label: o.label,
    correct: o.correct,
    explanation: o.explanation,
  }));

  return {
    id,
    subtest: 'usmle',
    title,
    instructions: 'Choose the single best answer for each question.',
    prompt,
    options: builtOptions,
    usmleStep: step,
    usmleDiscipline: discipline,
    usmleQuestionFormat: format,
    hasImage: !!imageSrc,
    imageSrc,
    imageCaption,
    explanation,
  };
}

function distractor(
  label: string,
  explanation: string,
): { label: string; correct: false; explanation: string } {
  return { label, correct: false, explanation };
}

function correct(
  label: string,
  explanation: string,
): { label: string; correct: true; explanation: string } {
  return { label, correct: true, explanation };
}

