// ── Exports ──────────────────────────────────────────────────────────

export const usmleBankByStep: Record<string, SessionTask[]> = {
  step1: step1Questions,
  step2: step2Questions,
  step3: step3Questions,
};

export function getUsmleTasks(
  step: string,
  discipline?: string,
  count?: number,
): SessionTask[] {
  const pool = usmleBankByStep[step] ?? [];
  const filtered = discipline
    ? pool.filter((t) => t.usmleDiscipline === discipline)
    : pool;

  const shuffled = [...filtered].sort(() => Math.random() - 0.5);
  return count ? shuffled.slice(0, count) : shuffled;
}

export function getUsmleDisciplinesForStep(step: string): string[] {
  const tasks = usmleBankByStep[step] ?? [];
  const disciplines = tasks.map((t) => t.usmleDiscipline).filter(Boolean);
  return [...new Set(disciplines)] as string[];
}
